mapper.update:
update user
nickname = #{nickname}, avatar = #{avatar}, email = #{email}, phone = #{phone}, password = #{password}, status = #{status}, role = #{role}, update_time = #{updateTime}
where user_id = #{userId}

mapper.select:
select * from user
and (username like concat('%',#{keyword},'%') or nickname like concat('%',#{keyword},'%') or phone like concat('%',#{keyword},'%'))
and role = #{role}
and status = #{status}
order by create_time desc
